function generateRandomWinSum() {
const currency = GAME_CONFIG.texts.currency
const min = 200;
const max = 896;
const baseAmountUSD = Math.random() * (max - min) + min;
if (!currency) {
return baseAmountUSD;
}
let currencyData = null;
if (currencyRates[currency]) {
currencyData = currencyRates[currency];
} else {
for (const [code, data] of Object.entries(currencyRates)) {
if (data.symbol === currency) {
currencyData = data;
break;
}
}
}
if (!currencyData) {
return baseAmountUSD;
}
return baseAmountUSD * currencyData.rate;
}
function formatCurrency(amount, showDecimals = true) {
const num = parseFloat(amount) || 0;
if (showDecimals && num % 1 !== 0) {
const integerPart = Math.floor(num);
const decimalPart = Math.round((num - integerPart) * 100);
const formattedInteger = integerPart.toLocaleString('de-DE');
return `${formattedInteger},${decimalPart.toString().padStart(2, '0')}`;
} else {
return Math.floor(num).toLocaleString('de-DE');
}
}
class AudioManager {
constructor() {
this.sounds = {};
this.musicVolume = 0.3;
this.sfxVolume = 0.7;
this.musicEnabled = true;
this.sfxEnabled = true;
this.backgroundMusic = null;
this.init();
}
init() {
this.loadSound('soundtrack', 'data:video/mp4;base64,', true);
this.loadSound('step', 'data:video/webm;base64,');
this.loadSound('win', 'data:video/webm;base64,');
this.loadSound('buttonClick', 'data:video/webm;base64,');
this.loadSound('lose', 'data:video/webm;base64,');
}
loadSound(name, src, isMusic = false) {
const audio = new Audio();
audio.src = src;
audio.preload = 'auto';
if (isMusic) {
audio.loop = true;
audio.volume = this.musicVolume;
this.backgroundMusic = audio;
} else {
audio.volume = this.sfxVolume;
}
audio.addEventListener('error', (e) => {
console.warn(`Failed to load audio: ${src}`, e);
});
this.sounds[name] = audio;
}
playSound(name, volume = 1.0) {
if (!this.sfxEnabled) return;
const sound = this.sounds[name];
if (sound) {
try {
const soundClone = sound.cloneNode();
soundClone.volume = this.sfxVolume * volume;
soundClone.currentTime = 0;
soundClone.play().catch(e => {
console.warn(`Failed to play sound: ${name}`, e);
});
} catch (error) {
console.warn(`Error playing sound: ${name}`, error);
}
}
}
playMusic() {
if (!this.musicEnabled || !this.backgroundMusic) return;
try {
this.backgroundMusic.currentTime = 0;
this.backgroundMusic.volume = this.musicVolume;
this.backgroundMusic.play().catch(e => {
console.warn('Failed to play background music', e);
});
} catch (error) {
console.warn('Error playing background music', error);
}
}
enableAudioContext() {
const enableAudio = () => {
if (this.musicEnabled) {
this.playMusic();
}
document.removeEventListener('click', enableAudio);
document.removeEventListener('touchstart', enableAudio);
document.removeEventListener('keydown', enableAudio);
};
document.addEventListener('click', enableAudio, { once: true });
document.addEventListener('touchstart', enableAudio, { once: true });
document.addEventListener('keydown', enableAudio, { once: true });
}
playButtonClick() {
this.playSound('buttonClick');
}
playStep() {
this.playSound('step');
}
playWin() {
this.playSound('win');
}
playLose() {
this.playSound('lose');
}
}
